 1	import type { FC } from 'react';
 2	import HelpSubTopic from 'src/onlineHelp/learningExperience/HelpSubTopic';
 3	import HelpTopicSection from 'src/onlineHelp/learningExperience/HelpTopicSection';
 4	import {
 5	  type LearningExperienceTopic,
 6	  ListStyleType,
 7	} from 'src/onlineHelp/learningExperience/types';
 8	import {
 9	  getClassForListStyle,
10	  getTextListComponentForListStyle,
11	} from 'src/onlineHelp/learningExperience/utils';
12	
13	import { Text, TextContent, TextList } from '@patternfly/react-core';
14	import { css } from '@patternfly/react-styles';
15	
16	type HelpTopicProps = {
17	  topic: LearningExperienceTopic;
18	};
19	
20	const HelpTopic: FC<HelpTopicProps> = ({ topic }) => (
21	  <>
22	    <TextContent>
23	      <Text component="h3">
24	        <span className="pf-v6-u-mr-sm">{topic.icon}</span>
25	        {topic.title}
26	      </Text>
27	    </TextContent>
28	    <div className="pf-v6-u-mt-lg">
29	      {topic.subTopics.map((subTopic, index) => {
30	        if (topic.subListStyleType === ListStyleType.DESCRIPTIONS) {
31	          return (
32	            <div key={subTopic.id} className="forklift--learning__help-description">
33	              {subTopic.title}
34	              {subTopic.subTopics ? (
35	                <div className={css('pf-v6-u-mb-md', Boolean(subTopic.title) && 'pf-v6-u-mt-md')}>
36	                  {subTopic.expandable ? (
37	                    subTopic.subTopics.map((nextSubTopic, subIndex) => (
38	                      <HelpTopicSection
39	                        key={nextSubTopic.id}
40	                        topic={nextSubTopic}
41	                        index={subIndex}
42	                        listStyleType={subTopic.subListStyleType}
43	                      />
44	                    ))
45	                  ) : (
46	                    <div className={getClassForListStyle(subTopic.subListStyleType)}>
47	                      <TextList
48	                        component={getTextListComponentForListStyle(subTopic.subListStyleType)}
49	                      >
50	                        {subTopic.subTopics.map((nextSubTopic) => (
51	                          <HelpSubTopic key={nextSubTopic.id} topic={nextSubTopic} />
52	                        ))}
53	                      </TextList>
54	                    </div>
55	                  )}
56	                </div>
57	              ) : null}
58	            </div>
59	          );
60	        }
61	        return (
62	          <HelpTopicSection
63	            key={subTopic.id}
64	            index={index}
65	            topic={subTopic}
66	            listStyleType={topic.subListStyleType}
67	          />
68	        );
69	      })}
70	    </div>
71	  </>
72	);
73	
74	export default HelpTopic;

